fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    val nInt = n.toInt()
    if (nInt == 0) return 0L

    var maxWeight = 0L
    for (edge in edges) {
        val w = edge[2]
        if (w > maxWeight) maxWeight = w
    }

    fun isFeasible(mid: Long): Boolean {
        val parent = IntArray(nInt) { it }
        val rank = IntArray(nInt) { 0 }
        var comp = nInt

        fun find(x: Int): Int {
            var root = x
            while (parent[root] != root) {
                root = parent[root]
            }
            var cur = x
            while (cur != root) {
                val next = parent[cur]
                parent[cur] = root
                cur = next
            }
            return root
        }

        for (edge in edges) {
            val w = edge[2]
            if (w > mid) continue

            val u = edge[0].toInt()
            val v = edge[1].toInt()
            val ru = find(u)
            val rv = find(v)

            if (ru == rv) continue

            if (rank[ru] < rank[rv]) {
                parent[ru] = rv
            } else if (rank[ru] > rank[rv]) {
                parent[rv] = ru
            } else {
                parent[rv] = ru
                rank[ru]++
            }
            comp--
        }
        return comp <= k
    }

    var low = 0L
    var high = maxWeight

    while (low < high) {
        val mid = (low + high) / 2
        if (isFeasible(mid)) {
            high = mid
        } else {
            low = mid + 1
        }
    }

    return low
}
